sys_script_include.script:
/**
 * @class AppInstallAdjustTableUtils
 * @description Script to change the TabelUtils access to public
 * @since 32/02/2026
 * @date  32/02/2026
 * @version 1.0.0
 * @author Thomas Grensemann E-Mail: <thomas.grensemann@t-systems.com>
 *
 */

class AppInstallAdjustTableUtils {

	/**
	 * Change the TabelUtils access to public
	 */
    adjustTableUtils() {
        const query = 'active=true^name=TableUtils^sys_scope=global';

        const params = {
            'table': 'sys_script_include',
            'query': query,
            'properties': JSON.stringify({access: 'public'}),
            'stealth': true,
            'result': ''
        };

        const script = ScriptBuider.getScriptRecordUpdateByQuery();

        new ScriptEvaluator().executScript('global', script, params);
    }

}
